import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import A from "./src/api/axios"

const Dashboard = () => {
  const navigate
   = useNavigate();
  
  const [syllabus, setSyllabus] = useState('');
  const [targetDate, setTargetDate] = useState('');
  const [schedule, setSchedule] = useState(null); 
  const [loading, setLoading] = useState(false);

  // --- NEW: Load schedule from localStorage or API to ensure persistence ---
  useEffect(() => {
    const token = localStorage.getItem('token');
    if (!token) {
      navigate('/login');
    } else {
      // Check if a schedule already exists so it isn't deleted on refresh
      const savedSchedule = localStorage.getItem('studyPulse_schedule');
      if (savedSchedule) {
        setSchedule(JSON.parse(savedSchedule));
      }
    }
  }, [navigate]);

  const handleLogout = () => {
    localStorage.removeItem('token');
    navigate('/login');
  };

  const generateSchedule = async () => {
    if (!syllabus || !targetDate) {
      alert("Please enter both the syllabus and a target date!");
      return;
    }

    setLoading(true);
    
    setTimeout(() => {
      const topics = syllabus.split(',').map(item => item.trim());
      const generatedDays = topics.map((topic, index) => ({
        day: index + 1,
        topic: topic || `Topic ${index + 1}`,
        isCompleted: false, // NEW: Track status
        date: new Date(Date.now() + index * 86400000).toLocaleDateString() // NEW: Assign dates
      }));

      setSchedule(generatedDays);
      localStorage.setItem('studyPulse_schedule', JSON.stringify(generatedDays)); // Persist data
      setLoading(false);
    }, 1500);
  };

  return (
    <div style={{ fontFamily: 'Arial, sans-serif', backgroundColor: '#f9f9f9', minHeight: '100vh' }}>
      <nav style={{ display: 'flex', justifyContent: 'space-between', padding: '15px 30px', background: '#2c3e50', color: 'white' }}>
        <h2 style={{ margin: 0 }}>StudyPulse</h2>
        <button onClick={handleLogout} style={{ background: '#e74c3c', color: 'white', border: 'none', padding: '8px 15px', borderRadius: '5px', cursor: 'pointer' }}>
          Logout
        </button>
      </nav>

      <div style={{ maxWidth: '800px', margin: '40px auto', padding: '20px', background: 'white', borderRadius: '10px', boxShadow: '0 4px 6px rgba(0,0,0,0.1)' }}>
        <h1 style={{ color: '#34495e' }}>Your Study Plan</h1>
        
        {!schedule ? (
          <div style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
            <input type="date" value={targetDate} onChange={(e) => setTargetDate(e.target.value)} style={{ width: '100%', padding: '10px', borderRadius: '5px', border: '1px solid #ddd' }} />
            <textarea placeholder="Topics separated by commas..." value={syllabus} onChange={(e) => setSyllabus(e.target.value)} style={{ width: '100%', height: '120px', padding: '10px', borderRadius: '5px', border: '1px solid #ddd' }} />
            <button onClick={generateSchedule} disabled={loading} style={{ backgroundColor: loading ? '#bdc3c7' : '#3498db', color: 'white', padding: '15px', borderRadius: '5px', cursor: 'pointer' }}>
              {loading ? 'Generating...' : 'Generate Study Schedule'}
            </button>
          </div>
        ) : (
          <div style={{ marginTop: '30px' }}>
            <h3 style={{ borderBottom: '2px solid #3498db', paddingBottom: '10px' }}>Day-Wise Progress:</h3>
            <div style={{ display: 'grid', gap: '15px' }}>
              {schedule.map((item) => (
                <div 
                  key={item.day}
                  // --- CHANGE: Conditional Styling for Completed Status ---
                  style={{ 
                    padding: '20px', 
                    background: item.isCompleted ? '#f0fff4' : '#fff', 
                    border: item.isCompleted ? '1px solid #38a169' : '1px solid #ddd', 
                    borderRadius: '8px', 
                    display: 'flex',
                    justifyContent: 'space-between',
                    alignItems: 'center',
                    opacity: item.isCompleted ? 0.8 : 1
                  }}
                >
                  <div>
                    <strong>Day {item.day}:</strong> {item.topic}
                    <div style={{ fontSize: '12px', color: '#666' }}>Target Date: {item.date}</div>
                  </div>

                  {/* --- CHANGE: Status Observer Logic --- */}
                  <div style={{ textAlign: 'right' }}>
                    {item.isCompleted ? (
                      <span style={{ color: '#38a169', fontWeight: 'bold' }}>✅ Completed</span>
                    ) : (
                      <button 
                        onClick={() => navigate(`/study-session/${item.day}`, { state: { topic: item.topic } })}
                        style={{ background: '#3498db', color: 'white', border: 'none', padding: '5px 10px', borderRadius: '4px', cursor: 'pointer' }}
                      >
                        Start Session →
                      </button>
                    )}
                  </div>
                </div>
              ))}
            </div>
            
            {/* NEW: Reset button only if needed, otherwise schedule is locked */}
            <button 
              onClick={() => { if(window.confirm("Reset entire plan?")) { localStorage.removeItem('studyPulse_schedule'); setSchedule(null); }}} 
              style={{ marginTop: '20px', background: 'none', border: 'none', color: '#e74c3c', cursor: 'pointer', fontSize: '12px' }}
            >
              Clear and Start New Plan
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

export default Dashboard;
